class SAMLNamespaces:
    SAML = '{urn:oasis:names:tc:SAML:2.0:assertion}'
    SAMLP = '{urn:oasis:names:tc:SAML:2.0:protocol}'
    DS = '{http://www.w3.org/2000/09/xmldsig#}'
    
    NAMESPACES = {
        'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
        'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
        'ds': 'http://www.w3.org/2000/09/xmldsig#',
    }


class SAMLValidator:
    @staticmethod
    def validate_xml_structure(root):
        """Basic XML structure validation for SAML Response"""
        ns = SAMLNamespaces
        
        if root.tag != f"{ns.SAMLP}Response":
            raise ValueError("Root element must be samlp:Response")
        
        version = root.get('Version')
        if version != '2.0':
            raise ValueError(f"Unsupported SAML version: {version}")
        
        issue_instant = root.get('IssueInstant')
        if not issue_instant:
            raise ValueError("IssueInstant is required")
        
        status = root.find(f"{ns.SAMLP}Status/{ns.SAMLP}StatusCode", ns.NAMESPACES)
        if status is None:
            raise ValueError("Status element is required")
        
        status_value = status.get('Value')
        if status_value != 'urn:oasis:names:tc:SAML:2.0:status:Success':
            raise ValueError(f"SAML Response status is not Success: {status_value}")
        
        assertion = root.find(f"{ns.SAML}Assertion", ns.NAMESPACES)
        if assertion is None:
            raise ValueError("Assertion element is required")
        
        return True
    
    @staticmethod
    def validate_assertion_conditions(assertion):
        """Validate assertion conditions including time constraints"""
        ns = SAMLNamespaces
        
        conditions = assertion.find(f"{ns.SAML}Conditions", ns.NAMESPACES)
        if conditions is None:
            return True
        
        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        
        now = datetime.utcnow()
        
        if not_before:
            not_before_dt = datetime.fromisoformat(not_before.replace('Z', '+00:00')).replace(tzinfo=None)
            if now < not_before_dt:
                raise ValueError("Assertion is not yet valid")
        
        if not_on_or_after:
            not_on_or_after_dt = datetime.fromisoformat(not_on_or_after.replace('Z', '+00:00')).replace(tzinfo=None)
            if now >= not_on_or_after_dt:
                raise ValueError("Assertion has expired")
        
        return True


class SAMLParser:
    @staticmethod
    def decode_saml_response(saml_response_base64):
        """Decode base64 encoded SAML response"""
        try:
            decoded = base64.b64decode(saml_response_base64)
            return decoded.decode('utf-8')
        except Exception as e:
            raise ValueError(f"Failed to decode SAML response: {str(e)}")
    
    @staticmethod
    def parse_xml(saml_xml):
        """Parse SAML XML string to ElementTree"""
        try:
            root = ET.fromstring(saml_xml)
            return root
        except ET.ParseError as e:
            raise ValueError(f"Failed to parse XML: {str(e)}")
    
    @staticmethod
    def extract_name_id(assertion):
        """Extract NameID from assertion"""
        ns = SAMLNamespaces
        
        subject = assertion.find(f"{ns.SAML}Subject", ns.NAMESPACES)
        if subject is None:
            raise ValueError("Subject element not found in assertion")
        
        name_id = subject.find(f"{ns.SAML}NameID", ns.NAMESPACES)
        if name_id is None:
            raise ValueError("NameID element not found in subject")
        
        return {
            'value': name_id.text,
            'format': name_id.get('Format', ''),
            'name_qualifier': name_id.get('NameQualifier', ''),
        }
    
    @staticmethod
    def extract_attributes(assertion):
        """Extract all attributes from assertion"""
        ns = SAMLNamespaces
        attributes = {}
        
        attribute_statement = assertion.find(f"{ns.SAML}AttributeStatement", ns.NAMESPACES)
        if attribute_statement is None:
            return attributes
        
        for attribute in attribute_statement.findall(f"{ns.SAML}Attribute", ns.NAMESPACES):
            attr_name = attribute.get('Name')
            attr_friendly_name = attribute.get('FriendlyName', attr_name)
            
            attr_values = []
            for attr_value in attribute.findall(f"{ns.SAML}AttributeValue", ns.NAMESPACES):
                if attr_value.text:
                    attr_values.append(attr_value.text)
            
            if len(attr_values) == 1:
                attributes[attr_name] = attr_values[0]
            elif len(attr_values) > 1:
                attributes[attr_name] = attr_values
            
            if attr_friendly_name != attr_name:
                if len(attr_values) == 1:
                    attributes[attr_friendly_name] = attr_values[0]
                elif len(attr_values) > 1:
                    attributes[attr_friendly_name] = attr_values
        
        return attributes
    
    @staticmethod
    def extract_session_index(assertion):
        """Extract session index from AuthnStatement"""
        ns = SAMLNamespaces
        
        authn_statement = assertion.find(f"{ns.SAML}AuthnStatement", ns.NAMESPACES)
        if authn_statement is not None:
            return authn_statement.get('SessionIndex')
        
        return None


class SAMLUserManager:
    @staticmethod
    def get_or_create_user(name_id, attributes):
        """Get or create Django user based on SAML assertion data"""
        username = name_id['value']
        
        email = attributes.get('email') or attributes.get('mail') or attributes.get('emailAddress', '')
        first_name = attributes.get('givenName') or attributes.get('firstName', '')
        last_name = attributes.get('sn') or attributes.get('surname') or attributes.get('lastName', '')
        
        if isinstance(email, list):
            email = email[0] if email else ''
        if isinstance(first_name, list):
            first_name = first_name[0] if first_name else ''
        if isinstance(last_name, list):
            last_name = last_name[0] if last_name else ''
        
        user, created = User.objects.get_or_create(
            username=username[:150],
            defaults={
                'email': email[:254] if email else '',
                'first_name': first_name[:150] if first_name else '',
                'last_name': last_name[:150] if last_name else '',
            }
        )
        
        if not created:
            user.email = email[:254] if email else user.email
            user.first_name = first_name[:150] if first_name else user.first_name
            user.last_name = last_name[:150] if last_name else user.last_name
            user.save()
        
        return user
    
    @staticmethod
    def create_user_session(request, user, name_id, attributes, session_index):
        """Create Django session with SAML attributes"""
        login(request, user, backend='django.contrib.auth.backends.ModelBackend')
        
        request.session['saml_name_id'] = name_id
        request.session['saml_attributes'] = attributes
        request.session['saml_session_index'] = session_index
        request.session['saml_authenticated'] = True
        request.session['saml_auth_time'] = datetime.utcnow().isoformat()
        
        request.session.set_expiry(28800)
        
        return request.session


