def assertion_consumer_service(request):
    """Handle SAML POST response"""
    try:
        saml_response_encoded = request.POST.get('SAMLResponse')
        if not saml_response_encoded:
            return HttpResponseBadRequest("SAMLResponse parameter is required")
        
        relay_state = request.POST.get('RelayState', '/')
        
        parser = SAMLParser()
        saml_xml = parser.decode_saml_response(saml_response_encoded)
        root = parser.parse_xml(saml_xml)
        
        validator = SAMLValidator()
        validator.validate_xml_structure(root)
        
        ns = SAMLNamespaces
        assertion = root.find(f"{ns.SAML}Assertion", ns.NAMESPACES)
        
        validator.validate_assertion_conditions(assertion)
        
        name_id = parser.extract_name_id(assertion)
        attributes = parser.extract_attributes(assertion)
        session_index = parser.extract_session_index(assertion)
        
        user_manager = SAMLUserManager()
        user = user_manager.get_or_create_user(name_id, attributes)
        user_manager.create_user_session(request, user, name_id, attributes, session_index)
        
        return redirect(relay_state)
        
    except ValueError as e:
        return HttpResponseBadRequest(f"SAML validation error: {str(e)}")
    except Exception as e:
        return HttpResponseBadRequest(f"Error processing SAML response: {str(e)}")


def generate_authn_request(request):
    """Generate SAML AuthnRequest"""
    request_id = f"_{uuid.uuid4()}"
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    sp_config = settings.SAML_SP_CONFIG
    idp_config = settings.SAML_IDP_CONFIG
    
    relay_state = request.GET.get('next', '/')
    
    authn_request = f"""<samlp:AuthnRequest 
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{issue_instant}"
        Destination="{idp_config['SSO_URL']}"
        AssertionConsumerServiceURL="{sp_config['ACS_URL']}"
        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
        <saml:Issuer>{sp_config['ENTITY_ID']}</saml:Issuer>
        <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress" AllowCreate="true"/>
    </samlp:AuthnRequest>"""
    
    encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')
    
    html = f"""
    <!DOCTYPE html>
    <html>
    <head><title>SAML SSO</title></head>
    <body onload="document.forms[0].submit()">
        <form method="post" action="{idp_config['SSO_URL']}">
            <input type="hidden" name="SAMLRequest" value="{encoded_request}"/>
            <input type="hidden" name="RelayState" value="{relay_state}"/>
            <noscript>
                <input type="submit" value="Continue"/>
            </noscript>
        </form>
    </body>
    </html>
    """
    
    return HttpResponse(html)


